+fn resolve_issue_id(
+    storage: &SqliteStorage,
+    resolver: &IdResolver,
+    all_ids: &[String],
+    input: &str,
+) -> Result<String> {
+    resolver
+        .resolve(
+            input,
+            |id| storage.id_exists(id).unwrap_or(false),
+            |hash| find_matching_ids(all_ids, hash),
+        )
+        .map(|resolved| resolved.id)
+}
