+fn parse_date(s: &str) -> Result<DateTime<Utc>> {
+    // Basic RFC3339 parsing for now
+    DateTime::parse_from_rfc3339(s)
+        .map(|dt| dt.with_timezone(&Utc))
+        .map_err(|_| BeadsError::validation("date", "invalid format (expected RFC3339)"))
+}
